const allowed = new Set(['lead_id','source','language','service','location_id','requested_date','requested_time','duration_minutes','booking_reference','contact_consent','created_at']);
const prohibited = ['name','phone','email','child_name','diagnosis','medical_notes','message'];
const locations = new Set(['ics-al-najda','ics-al-falah','ics-khalifa','ics-mushrif','ics-al-danah']);
const services = new Set(['children-small-group','aquatic-movement','land-movement']);

return items.map((item) => {
  const keys = Object.keys(item.json);
  const unexpected = keys.filter((key) => !allowed.has(key));
  const presentProhibited = prohibited.filter((key) => item.json[key] !== undefined);

  if (unexpected.length || presentProhibited.length) {
    throw new Error(`Preview payload rejected. Unexpected: ${unexpected.join(',')}; prohibited: ${presentProhibited.join(',')}`);
  }
  if (item.json.contact_consent !== true) throw new Error('Preview payload rejected: contact consent must be true.');
  if (!locations.has(item.json.location_id)) throw new Error('Preview payload rejected: unknown location.');
  if (!services.has(item.json.service)) throw new Error('Preview payload rejected: unknown service.');
  if (!/^RF-[A-Z0-9-]{4,32}$/.test(item.json.booking_reference)) throw new Error('Preview payload rejected: invalid booking reference.');

  const start = Number(item.json.requested_time.slice(0, 2)) * 60 + Number(item.json.requested_time.slice(3, 5));
  const weekday = new Date(`${item.json.requested_date}T12:00:00Z`).getUTCDay();
  const allowedStart = weekday === 0 || weekday === 6 ? 600 : 960;
  const allowedEnd = weekday === 0 || weekday === 6 ? 1320 : 1260;
  if (!Number.isFinite(start) || start < allowedStart || start + item.json.duration_minutes > allowedEnd) {
    throw new Error('Preview payload rejected: outside general availability.');
  }

  return {
    json: {
      ...item.json,
      idempotency_key: `${item.json.source}:${item.json.booking_reference}`,
      calendar_conflict_check_required: true,
      location_calendar_check_required: true,
      appointment_confirmed: false,
      preview_only: true,
      contains_real_pii: false
    }
  };
});
